SELECT forecaster_id, COUNT(*) AS forecast_count
FROM election_forecasts
GROUP BY forecaster_id;

SELECT forecaster_name
FROM forecasters
WHERE forecaster_id = 1;

SELECT forecast_id, last_updated
FROM election_forecasts
ORDER BY last_updated DESC;

SELECT forecast_id, state_id, biden_votes, trump_votes
FROM state_predictions
WHERE forecast_id = 1;

SELECT COUNT(*) 
FROM state_predictions 
WHERE toss_up = 1;

SELECT last_updated
FROM election_forecasts
WHERE forecaster_id = (SELECT forecaster_id FROM forecasters WHERE forecaster_name = 'FiveThirtyEight');

SELECT predicted_winner, confidence_level
FROM election_forecasts
WHERE forecast_id = 1;
